import {
  isProgramError,
  type Address,
  type SOLANA_ERROR__INSTRUCTION_ERROR__CUSTOM,
  type SolanaError,
} from "@solana/kit";
import { journal_PROGRAM_ADDRESS } from "../programs";

/** journalAlreadyExists: journal already exists */
export const journal_ERROR__journal_ALREADY_EXISTS = 0x1770; // 6000
/** InvalidAmount: Invalid amount */
export const journal_ERROR__INVALID_AMOUNT = 0x1771; // 6001

export type journalError =
  | typeof journal_ERROR__INVALID_AMOUNT
  | typeof journal_ERROR__journal_ALREADY_EXISTS;

let journalErrorMessages: Record<journalError, string> | undefined;
if (process.env.NODE_ENV !== "production") {
  journalErrorMessages = {
    [journal_ERROR__INVALID_AMOUNT]: `Invalid amount`,
    [journal_ERROR__journal_ALREADY_EXISTS]: `journal already exists`,
  };
}

export function getjournalErrorMessage(code: journalError): string {
  if (process.env.NODE_ENV !== "production") {
    return (journalErrorMessages as Record<journalError, string>)[code];
  }

  return "Error message not available in production bundles.";
}

export function isjournalError<TProgramErrorCode extends journalError>(
  error: unknown,
  transactionMessage: {
    instructions: Record<number, { programAddress: Address }>;
  },
  code?: TProgramErrorCode,
): error is SolanaError<typeof SOLANA_ERROR__INSTRUCTION_ERROR__CUSTOM> &
  Readonly<{ context: Readonly<{ code: TProgramErrorCode }> }> {
  return isProgramError<TProgramErrorCode>(
    error,
    transactionMessage,
    journal_PROGRAM_ADDRESS,
    code,
  );
}
